28	const ChatMediaPanel = ({ roomId }: ChatMediaPanelProps) => {
29	  const [activeTab, setActiveTab] = useState<TabType>("media");
30	  const [allMessages, setAllMessages] = useState<MediaMessage[]>([]);
31	  const [loading, setLoading] = useState(true);
32	
33	  useEffect(() => {
34	    const fetchMedia = async () => {
35	      setLoading(true);
36	      const { data } = await supabase
37	        .from("chat_messages")
38	        .select("id, content, message_type, file_url, file_name, file_type, file_size, invoice_id, contract_id, created_at")
39	        .eq("room_id", roomId)
40	        .in("message_type", ["file", "invoice", "contract", "text"])
41	        .order("created_at", { ascending: false });
42	
43	      setAllMessages(data || []);
44	      setLoading(false);
45	    };
46	    fetchMedia();
47	  }, [roomId]);
48	
49	  // Extract links from text messages
50	  const urlRegex = /(https?:\/\/[^\s]+)/g;
51	
52	  const mediaItems = useMemo(
53	    () => allMessages.filter((m) => m.message_type === "file" && m.file_type?.startsWith("image/")),
54	    [allMessages]
55	  );
56	
57	  const docItems = useMemo(
58	    () => [
59	      ...allMessages.filter(
60	        (m) =>
61	          (m.message_type === "file" && !m.file_type?.startsWith("image/")) ||
62	          m.message_type === "invoice" ||
63	          m.message_type === "contract"
64	      ),
65	    ],
66	    [allMessages]
67	  );
68	
69	  const linkItems = useMemo(() => {
70	    const links: { id: string; url: string; created_at: string }[] = [];
71	    allMessages.forEach((m) => {
72	      if (m.content) {
73	        const matches = m.content.match(urlRegex);
74	        if (matches) {
75	          matches.forEach((url) => links.push({ id: m.id + url, url, created_at: m.created_at }));
76	        }
77	      }
78	    });
79	    return links;
80	  }, [allMessages]);
