82	  const tabs: { id: TabType; label: string; count: number }[] = [
83	    { id: "media", label: "Media", count: mediaItems.length },
84	    { id: "docs", label: "Docs", count: docItems.length },
85	    { id: "links", label: "Links", count: linkItems.length },
