88	  const downloadFile = async (fileUrl: string, fileName: string) => {
89	    const { data, error } = await supabase.storage.from("chat-files").download(fileUrl);
90	    if (error) {
91	      toast.error("Download failed");
92	      return;
93	    }
94	    const url = URL.createObjectURL(data);
95	    const a = document.createElement("a");
96	    a.href = url;
97	    a.download = fileName;
98	    document.body.appendChild(a);
99	    a.click();
100	    document.body.removeChild(a);
101	    URL.revokeObjectURL(url);
