208	                        {group.label}
209	                      </p>
210	                      <div className="space-y-1.5">
211	                        {group.items.map((item) => {
212	                          const isInvoice = item.message_type === "invoice";
213	                          const isContract = item.message_type === "contract";
214	                          const Icon = isInvoice ? Receipt : isContract ? FileSignature : File;
215	
216	                          return (
217	                            <button
218	                              key={item.id}
219	                              onClick={() => {
220	                                if (item.file_url) downloadFile(item.file_url, item.file_name || "file");
221	                              }}
222	                              className="w-full flex items-center gap-3 p-2.5 rounded-xl hover:bg-muted/50 transition-colors text-left"
223	                            >
224	                              <div className="h-10 w-10 rounded-lg bg-bronze/10 flex items-center justify-center flex-shrink-0">
225	                                <Icon className="h-5 w-5 text-bronze" />
226	                              </div>
227	                              <div className="flex-1 min-w-0">
228	                                <p className="text-xs font-medium truncate">
229	                                  {isInvoice
