234	                                </p>
235	                                <p className="text-[10px] text-muted-foreground">
236	                                  {item.file_size ? formatFileSize(item.file_size) + " • " : ""}
237	                                  {format(new Date(item.created_at), "MMM d, yyyy")}
238	                                </p>
239	                              </div>
240	                              {item.file_url && (
241	                                <Download className="h-4 w-4 text-muted-foreground flex-shrink-0" />
242	                              )}
243	                            </button>
244	                          );
245	                        })}
246	                      </div>
247	                    </div>
248	                  ))}
249	                </div>
250	              )
251	            )}
252	
253	            {/* Links Tab */}
254	            {activeTab === "links" && (
255	              linkItems.length === 0 ? (
256	                <div className="flex flex-col items-center justify-center h-48 text-muted-foreground">
257	                  <Link2 className="h-8 w-8 mb-2 opacity-30" />
258	                  <p className="text-xs">No links shared yet</p>
259	                </div>
260	              ) : (
261	                <div className="space-y-3 px-1">
262	                  {groupByMonth(linkItems).map((group) => (
263	                    <div key={group.label}>
264	                      <p className="text-[10px] font-bold text-muted-foreground tracking-wider mb-2">
265	                        {group.label}
266	                      </p>
267	                      <div className="space-y-1.5">
268	                        {group.items.map((item) => {
269	                          let displayUrl = item.url;
270	                          try {
271	                            const parsed = new URL(item.url);
272	                            displayUrl = parsed.hostname + (parsed.pathname !== "/" ? parsed.pathname : "");
273	                          } catch {}
274	
275	                          return (
276	                            <a
277	                              key={item.id}
278	                              href={item.url}
279	                              target="_blank"
280	                              rel="noopener noreferrer"
281	                              className="flex items-center gap-3 p-2.5 rounded-xl hover:bg-muted/50 transition-colors"
282	                            >
283	                              <div className="h-10 w-10 rounded-lg bg-bronze/10 flex items-center justify-center flex-shrink-0">
284	                                <Link2 className="h-5 w-5 text-bronze" />
285	                              </div>
286	                              <div className="flex-1 min-w-0">
287	                                <p className="text-xs font-medium truncate text-foreground">
288	                                  {displayUrl}
289	                                </p>
290	                                <p className="text-[10px] text-muted-foreground">
291	                                  {format(new Date(item.created_at), "MMM d, yyyy")}
292	                                </p>
293	                              </div>
294	                              <ExternalLink className="h-4 w-4 text-muted-foreground flex-shrink-0" />
295	                            </a>
296	                          );
297	                        })}
298	                      </div>
299	                    </div>
300	                  ))}
301	                </div>
302	              )
303	            )}
304	          </>
305	        )}
306	      </ScrollArea>
307	    </div>
308	  );
